select * from ( SELECT v.designer AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM volume v, project p, `USER` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE p.id = v.project_id AND u.`name` = v.designer AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND (( v.shot_date != "" AND ( v.planned_start_date >= #{sqlDate} OR v.start_date >= #{sqlDate} OR v.shot_date >= #{sqlDate} OR v.actual_publication_date >= #{sqlDate} )) OR ( v.shot_date = "" AND v.start_date != "" )) UNION SELECT principal AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM project p, volume v, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND p.id = v.project_id AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND u.`name` = v.principal AND v.principal NOT LIKE "%;%" UNION SELECT SUBSTRING_INDEX( v.principal, ";", 1 ) AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM volume v, project p, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE p.id = v.project_id AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND u.`name` = SUBSTRING_INDEX( v.principal, ";", 1 ) AND v.principal LIKE "%;%" UNION SELECT SUBSTRING_INDEX( v.principal, ";",- 1 ) AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM project p, volume v, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE p.id = v.project_id AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND u.`name` = SUBSTRING_INDEX( v.principal, ";",- 1 ) AND v.principal LIKE "%;%" UNION SELECT p.general AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM project p, volume v, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND p.id = v.project_id AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND u.`name` = p.general AND p.general NOT LIKE "%;%" UNION SELECT SUBSTRING_INDEX( p.general, ";", 1 ) AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM project p, volume v, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND p.id = v.project_id AND u.id <> #{id} AND u.`name` = SUBSTRING_INDEX( p.general, ";", 1 ) AND p.general LIKE "%;%" UNION SELECT SUBSTRING_INDEX( p.general, ";", - 1 ) AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role FROM project p, volume v, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE FIND_IN_SET(#{name},REPLACE (p.general, ";", "," )) AND p.id = v.project_id AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND u.`name` = SUBSTRING_INDEX( p.general, ";", - 1 ) AND p.general LIKE "%;%" union SELECT v.designer AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 14 as role FROM volume v, project p, `USER` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE p.id = v.project_id AND u.`name` = v.de