) AND p.id = v.project_id AND u.id <> #{id} AND u.`name` = SUBSTRING_INDEX( p.general, ";", 1 ) AND p.general LIKE "%;%" UNION SELECT SUBSTRING_INDEX( p.general, ";", - 1 ) AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 14 as role FROM project p, volume v, `user` u LEFT JOIN user_score us ON us.grade_id = #{id} AND u.id = us.score_id, department d, technology t WHERE p.id in ( SELECT project_id FROM volume WHERE FIND_IN_SET(#{name},REPLACE (principal, ";", "," ))
) AND p.id = v.project_id AND u.id <> #{id} AND u.did = d.id AND u.tid = t.id AND u.`name` = SUBSTRING_INDEX( p.general, ";", - 1 ) AND p.general LIKE "%;%" union select u.name AS `name`, u.id, u.username, d.name AS department, t.name AS technology, us.designer, us.personal, us.coordinate, 13 as role from score_manage sm, `user` u left join user_score us on u.id = score_id and grade_id = #{id}, department d, technology t where sm.score_id = #{id} and sm.scored_id = u.id and u.did = d.id and u.tid = t.id and sm.state = 0 ) as d
